ruleContent:
@js:
(function(){
    try {
        var data = JSON.parse(result);
        var videoId = data.video.id; 
        var playlists = data.video.playlists;
        var labels = data.player_label_arr;
        var cover = data.video.cover;
        var jxUrl = "https://jx.ejtsyc.com:8443/m3u8/?url=";

        // 获取默认播放链接
        var defaultPlayUrl = "";
        for (var k in playlists) {
            if (playlists[k] && playlists[k].length > 0) {
                defaultPlayUrl = jxUrl + playlists[k][0][1];
                break;
            }
        }

        var html = '<meta name="referrer" content="never">';
        html += '<div style="width:100%; font-family: sans-serif;">';

        // 1. 播放器窗口
        if (defaultPlayUrl !== "") {
            html += '<iframe name="ageplayer" id="ageplayer" src="' + defaultPlayUrl + '" width="100%" height="240px" frameborder="0" allowfullscreen="true" style="border-radius:8px; background:#000;"></iframe>';
        } else {
            html += '<img src="' + cover + '" style="width:100%; border-radius:8px;"/>';
        }

        // 2. 观看历史提示词区域 (占位)
        html += '<p id="history-text" style="color:#f60; font-size:14px; margin-top:12px; font-weight:bold; text-align:center;">读取进度中...</p>';

        // ----- 构建线路 Tabs 和 剧集 Containers -----
        var tabsHtml = '<div style="display:flex; overflow-x:auto; gap:15px; border-bottom:1px solid #eee; padding-bottom:8px; margin-top:10px; white-space:nowrap; -webkit-overflow-scrolling: touch;">';
        var epsHtml = '<div style="margin-top:15px;">';

        var tabIndex = 0;
        var firstTabId = "";
        var firstLineName = "";
        var firstEpName = "";

        for (var key in playlists) {
            var lineName = labels[key] ? labels[key] : key;
            var tId = "line_" + tabIndex;
            var episodes = playlists[key];

            // 记录第一条线路信息，用于没有历史记录时的默认兜底显示
            if (tabIndex === 0) {
                firstTabId = tId;
                firstLineName = lineName;
                if (episodes.length > 0) firstEpName = episodes[0][0];
            }

            // 生成顶部线路 Tab 按钮
            tabsHtml += '<div id="tab_' + tId + '" class="line-tab" onclick="switchTab(\'' + tId + '\')" style="padding:4px 8px; color:#666; font-size:15px; cursor:pointer; transition:all 0.2s;">' + lineName + '</div>';

            // 生成该线路对应的剧集容器 (默认隐藏 display:none)
            epsHtml += '<div id="container_' + tId + '" class="ep-container" style="display:none; flex-wrap:wrap; gap:10px;">';

            for (var i = 0; i < episodes.length; i++) {
                var epName = episodes[i][0];
                var epCode = episodes[i][1];
                var playUrl = jxUrl + epCode;

                // 点击时传入更多参数以供记忆 (按钮本身, 链接, 线路名, 剧集名, 所属Tab)
                epsHtml += '<a href="' + playUrl + '" target="ageplayer" class="ep-btn" onclick="savePlayHistory(this, \'' + playUrl + '\', \'' + lineName + '\', \'' + epName + '\', \'' + tId + '\')" style="padding:6px 12px; background:#f0f2f5; text-decoration:none; color:#333; border-radius:6px; font-size:14px; border:1px solid #e4e6eb; text-align:center; transition: all 0.2s;">' + epName + '</a>';
            }
            epsHtml += '</div>';
            tabIndex++;
        }

        tabsHtml += '</div>';
        epsHtml += '</div>';

        // 拼接 HTML 结构
        html += tabsHtml;
        html += epsHtml;
        html += '</div>';

        // ---------------- 注入客户端 JS ----------------
        html += '<script>';
        html += 'var storageKey = "age_history_" + "' + videoId + '";';

        // 切换线路 Tab 的函数
        html += 'function switchTab(tId) {';
        html += '   var eps = document.querySelectorAll(".ep-container");';
        html += '   for(var i=0; i<eps.length; i++) eps[i].style.display = "none";'; // 隐藏所有剧集容器
        html += '   var tabs = document.querySelectorAll(".line-tab");';
        html += '   for(var i=0; i<tabs.length; i++) { tabs[i].style.color = "#666"; tabs[i].style.borderBottom = "none"; tabs[i].style.fontWeight = "normal"; }'; // 重置所有Tab样式
        html += '   document.getElementById("container_" + tId).style.display = "flex";'; // 显示选中的剧集容器
        html += '   var activeTab = document.getElementById("tab_" + tId);';
        html += '   if(activeTab) { activeTab.style.color = "#f60"; activeTab.style.borderBottom = "2px solid #f60"; activeTab.style.fontWeight = "bold"; }'; // 高亮选中Tab
        html += '}';

        // 剧集点击保存记录的函数
        html += 'function savePlayHistory(btnElem, url, lineName, epName, tId) {';
        html += '   var histText = lineName + " - " + epName;';
        // 将复杂数据转为 JSON 字符串保存
        html += '   var saveData = { url: url, text: histText, tabId: tId };';
        html += '   localStorage.setItem(storageKey, JSON.stringify(saveData));';

        html += '   document.getElementById("history-text").innerText = "您当前已观看到：" + histText;';
        html += '   var btns = document.querySelectorAll(".ep-btn");';
        html += '   for(var i=0; i<btns.length; i++){ btns[i].style.background="#f0f2f5"; btns[i].style.color="#333"; btns[i].style.borderColor="#e4e6eb"; }';
        html += '   btnElem.style.background="#f60"; btnElem.style.color="#fff"; btnElem.style.borderColor="#f60";';
        html += '}';

        // 页面初始加载逻辑
        html += 'window.onload = function() {';
        html += '   var savedStr = localStorage.getItem(storageKey);';
        html += '   if (savedStr) {';
        html += '       try {';
        html += '           var savedData = JSON.parse(savedStr);';
        html += '           document.getElementById("history-text").innerText = "您当前已观看到：" + savedData.text;';
        html += '           var player = document.getElementById("ageplayer");';
        html += '           if (player) player.src = savedData.url;';
        html += '           switchTab(savedData.tabId);'; // 恢复对应线路 Tab
        html += '           var btns = document.querySelectorAll(".ep-btn");';
        html += '           for(var i=0; i<btns.length; i++){ ';
        html += '               if(btns[i].getAttribute("href") === savedData.url) {';
        html += '                   btns[i].style.background="#f60"; btns[i].style.color="#fff"; btns[i].style.borderColor="#f60";';
        html += '                   break;';
        html += '               }';
        html += '           }';
        html += '       } catch(e) {}';
        html += '   } else {';
        // 初次加载没有任何历史记录时的默认状态
        html += '       switchTab("' + firstTabId + '");';
        html += '       document.getElementById("history-text").innerText = "您当前已观看到：" + "' + firstLineName + ' - ' + firstEpName + '";';
        html += '       var firstBtn = document.querySelector("#container_" + "' + firstTabId + '" + " .ep-btn");';
        html += '       if(firstBtn) { firstBtn.style.background="#f60"; firstBtn.style.color="#fff"; firstBtn.style.borderColor="#f60"; }';
        html += '   }';
        html += '};';
        html += '</script>';

        return html;

    } catch(e) {
        return "解析错误：" + e.message;
    }
})();
